        if (item.values && Array.isArray(item.values)) {
            const numericValues = item.values.filter(v => typeof v === 'number');
            if (numericValues.length > 0) {
                aggregations.sum = numericValues.reduce((a, b) => a + b, 0);
                aggregations.avg = aggregations.sum / numericValues.length;
                aggregations.min = Math.min(...numericValues);
                aggregations.max = Math.max(...numericValues);
                aggregations.count = numericValues.length;

                // Standard deviation
                const mean = aggregations.avg;
                const squaredDiffs = numericValues.map(v => Math.pow(v - mean, 2));
                aggregations.stdDev = Math.sqrt(
                    squaredDiffs.reduce((a, b) => a + b, 0) / numericValues.length
                );
            }
        }

        return aggregations;
